public class BreakDemo {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		for(int i=5; i<10 ; i++)
		{
			if(i == 5)
			{
				System.out.println(i);
			}
			
			System.out.println("Hello Friends");
			break;
		}
		System.out.println("AHJDGAJB");
		System.out.println("AHJDGAJB");
		System.out.println("AHJDGAJB");
		
		
	}

}
